item.description:
 &lt;h2 id=&#34;laravel目录结构&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#laravel目录结构&#34;&gt;#&lt;/a&gt; laravel 目录结构&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;app:laravel 项目的核心代码
&lt;ul&gt;
&lt;li&gt;app\Http\Controller.php: 定义控制器&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;bootstrap:
&lt;ul&gt;
&lt;li&gt;app.php: 用于框架的启动和自动载入配置&lt;/li&gt;
&lt;li&gt;cache: 处理缓存&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;config: 配置文件&lt;/li&gt;
&lt;li&gt;database: 数据库&lt;/li&gt;
&lt;li&gt;public: 定义了项目的入口文件:
&lt;ul&gt;
&lt;li&gt;index.php，localhost:8000，就会访问入口文件，前端静态资源&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;resources: 本地化语言文件&lt;/li&gt;
&lt;li&gt;routes：路由&lt;/li&gt;
&lt;li&gt;storage: 要与 app 文件夹产生联系&lt;/li&gt;
&lt;li&gt;tests: 测试&lt;/li&gt;
&lt;li&gt;vendor: 依赖&lt;/li&gt;
&lt;/ol&gt;
&lt;p&gt;全局配置阿里云 Composer 全量镜像&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;composer config -g repo.packagist composer https://mirrors.aliyun.com/composer/
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;composer 部署 laravel 项目&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;# 创建一个名为laravel的laravel项目 
composer crate-project laravel/laravel --prefer-dist ./
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;在项目根目录用 artisan 生成控制器文件&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;# 命令格式: 
php artisan make:controller 控制器名(大驼峰)+Controller关键词 
# 例: 
php artisan make:controller IndexController
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;路由&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#路由&#34;&gt;#&lt;/a&gt; 路由&lt;/h2&gt;
&lt;ol&gt;
&lt;li&gt;注册路由:
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;常规用法:&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Route:: 请求方式 (请求地址，function (){ return view (“页面名字”); });&lt;/li&gt;
&lt;li&gt;请求方式: get、post、put、delete、patch&lt;/li&gt;
&lt;li&gt;前端页面:&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;多匹配用法：只能接收定义得请求方式&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Route::match ([请求方式 1，请求方式 2…], 请求地址，function (){});&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;全匹配用法：所有请求方式都能接收&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Route::any (请求地址，function (){});&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;具体请求用法：将请求发送到某个控制器的某方法中&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;Route:: 三种用法皆可 (请求地址，控制器名 @方法名);&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;重定向路由：将前端发送的请求，发送到另一个路由中
&lt;ul&gt;
&lt;li&gt;Route::Redirect (前端请求地址，另一个路由请求地址);&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;视图路由：跳转页面同时，给新页面传递参数
&lt;ul&gt;
&lt;li&gt;Route::view (请求地址，跳转页面名字，[ “key” =&amp;gt; “value”,… ]);&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;带参数的路由:
&lt;ul&gt;
&lt;li&gt;Route:: 请求方式 (请求地址 /{参数名 1}/{参数名 2},function (参数 1, 参数 2){});&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h2 id=&#34;db类&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#db类&#34;&gt;#&lt;/a&gt; DB 类&lt;/h2&gt;
&lt;h3 id=&#34;增&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#增&#34;&gt;#&lt;/a&gt; 增&lt;/h3&gt;
&lt;p&gt;对数据库中的某个表增加数据主要有两个函数可以实现，分别是 insert () 和 insertGetld () insert () 可以同时添加一条或多条，返回值是布尔类型. insertGetid (), 只能添加一条数据，返回自增的 id. 注意：DB:table (‘无前缀的表名’)-&amp;gt;insert ();// 连贯操作 / 链式操作&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;//添加方法
    public function add()&amp;#123;
        //定义关联操作的表
        $db = DB::table(&#39;laravel&#39;);
        //插入数据
        $result = $db -&amp;gt; insert([
            [
                &#39;name&#39;=&amp;gt;&#39;马春梅&#39;,
                &#39;age&#39;=&amp;gt;&#39;19&#39;,
                &#39;email&#39;=&amp;gt;&#39;machunmei@qq.com&#39;
            ],
            [
                &#39;name&#39;=&amp;gt;&#39;马夏梅&#39;,
                &#39;age&#39;=&amp;gt;&#39;20&#39;,
                &#39;email&#39;=&amp;gt;&#39;maxiamei@qq.com&#39;
            ],
            [
                &#39;name&#39;=&amp;gt;&#39;马秋梅&#39;,
                &#39;age&#39;=&amp;gt;&#39;21&#39;,
                &#39;email&#39;=&amp;gt;&#39;maqiumei@qq.com&#39;
            ],
            [
                &#39;name&#39;=&amp;gt;&#39;马冬梅&#39;,
                &#39;age&#39;=&amp;gt;&#39;22&#39;,
                &#39;email&#39;=&amp;gt;&#39;madongmei@qq.com&#39;
            ],
        ]);
        dd($result);
    &amp;#125;
//insertGetid()方法如下:返回的是数据id
 $result = $db-&amp;gt;insertGetId([
                    &#39;name&#39;=&amp;gt;&#39;马*梅&#39;,
                    &#39;age&#39;=&amp;gt;&#39;33&#39;,
                    &#39;email&#39;=&amp;gt;&#39;ma*mei@qq.com&#39;
        ]);
        dd($result);
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;删&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#删&#34;&gt;#&lt;/a&gt; 删&lt;/h3&gt;
&lt;pre&gt;&lt;code&gt;业务中一般采用伪删除/逻辑删除
数据删除可以通过delete函数和truncate函数实现.
Delete    表示删除记录;
Truncate  表示清空整个数据表;
-&amp;gt;delete();
案例:
//删除id为1的记录
$data = $db-&amp;gt;where(&#39;id&#39;,&#39;=&#39;,&#39;1&#39;)-&amp;gt;delete();
dd($data);//返回的是受影响的行数
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;改&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#改&#34;&gt;#&lt;/a&gt; 改&lt;/h3&gt;
&lt;p&gt;数据修改可以使用 update ()、increment () 和 decrement () 函数来实现. Update 表示可以修改整个记录中的全部字段；Increment 和 decrement 表示修改数字字段的数值 (递增或者递减);&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;补充:
在laravel 中如果想友好输出打印内容，可以使用dd方法语法:dd(打印内容);[dump+die]

案例:把id=1的名称,改名为&#39;张三丰&#39;
-&amp;gt;where()-&amp;gt;update([])

where语法:
-&amp;gt;where(字段,运算符,值)  //如果运算符为&amp;quot;=&amp;quot;,则第二个参数可以不写

public function update()&amp;#123;
    $db = DB::table(&#39;laravel&#39;);
    $result = $db -&amp;gt; where(&#39;id&#39;,&#39;=&#39;,&#39;1&#39;)-&amp;gt;update([
        //需要修改字段的键值对
        &#39;name&#39;=&amp;gt;&#39;张三丰&#39;,
    ]);
    dd($result);//返回的是受影响的行数
&amp;#125;

DB::table(&#39;member&#39;)-&amp;gt;increment(&#39;votes&#39;);    每次+1
DB::table(&#39;member&#39;)-&amp;gt;increment(&#39;votes&#39;,5);  每次+5
DB::table(&#39;member&#39;)-&amp;gt;decrement(&#39;votes&#39;);    每次-1
DB::table(&#39;member&#39;)-&amp;gt;decrement(&#39;votes&#39; 5):  每次-5
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;&lt;/p&gt;
&lt;h3 id=&#34;查&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#查&#34;&gt;#&lt;/a&gt; 查&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;取出基本数据&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;//查询所有数据,GET查询的结果每一行的记录是对象的形式,不是数组
$data = $db-&amp;gt;get();    //get:查询所有数据,返回的是结果集
foreach ($data as $k =&amp;gt; $v)&amp;#123;
echo &amp;quot;id是: &amp;#123;$v-&amp;gt;id&amp;#125;名字是:&amp;#123;$v-&amp;gt;name&amp;#125;邮箱是:&amp;#123;$v-&amp;gt;email&amp;#125;年龄是:&amp;#123;$v-&amp;gt;age&amp;#125;&amp;quot;;
&amp;#125;
案例二:
//查询id&amp;gt;3
$data = $db -&amp;gt; where(&#39;id&#39;,&#39;&amp;gt;&#39;,&#39;3&#39;)-&amp;gt;get();
dd($data);
//注意:where方法之后继续调用where方法.
-&amp;gt; where() -&amp;gt; where() -&amp;gt; where()..   //这个语法是并且关系语法。
-&amp;gt; where() -&amp;gt; orWhere() -&amp;gt; orWhere()…      //这个语法是或者关系语法。
orWhere参数与where一样
案例三:
//查询id&amp;gt;2并且age&amp;lt;21 $data = $db-&amp;gt;where(&#39;id&#39;,&#39;&amp;gt;&#39;,&#39;2&#39;)-&amp;gt;Where(&#39;age&#39;,&#39;&amp;lt;&#39;,&#39;21&#39;)-&amp;gt;get();
dd($data);
//查询id&amp;gt;2或者age&amp;lt;20的 $data = $db-&amp;gt;where(&#39;id&#39;,&#39;&amp;gt;&#39;,&#39;2&#39;)-&amp;gt;orWhere(&#39;age&#39;,&#39;&amp;lt;&#39;,&#39;20&#39;)-&amp;gt;get();
dd($data);
&lt;/code&gt;&lt;/pre&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;取出单行数据&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;-&amp;gt;first()  //返回的是第一条记录,返回值是一个对象
//返回第一条记录
$data = $db-&amp;gt;first();
dd($data);
&lt;/code&gt;&lt;/pre&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;获取某个具体的值 (一个字段)&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;-&amp;gt;value(&#39;字段名&#39;)
案例:
$data = $db -&amp;gt; where(&#39;id&#39;,&#39;=&#39;,&#39;3&#39;)-&amp;gt;value(&#39;name&#39;);
dd($data);
&lt;/code&gt;&lt;/pre&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;获取某些字段数据 (多个字段)&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;-&amp;gt;select(&#39;字段名1&#39;,&#39;字段名2&#39;.....)
-&amp;gt;select(&#39;字段名1 as 别名&#39;,&#39;字段名2 as 别名&#39;.....)
//返回某些字段数据
$data = $db -&amp;gt;select(&#39;name&#39;,&#39;email&#39;)-&amp;gt;get();
dd($data);
&lt;/code&gt;&lt;/pre&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;排序操作&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;desc //降序
asc  //升序
-&amp;gt;orderBy(&#39;字段名&#39;,&#39;排序方式&#39;)
案例:
//排序:降序
$data = $db -&amp;gt;orderBy(&#39;id&#39;,&#39;desc&#39;)-&amp;gt;get();
dd($data);
&lt;/code&gt;&lt;/pre&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;分页操作&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;-&amp;gt;limit()-&amp;gt;offset()
limit   //表示限制输出的条数
offset  //从什么地方开始
案例:
//限制输出分页查询从第0条开始数3条数据
$data = $db-&amp;gt;limit(3)-&amp;gt;offset(0)-&amp;gt;get();
dd($data);
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;view&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#view&#34;&gt;#&lt;/a&gt; view&lt;/h2&gt;
&lt;h3 id=&#34;视图文件目录&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#视图文件目录&#34;&gt;#&lt;/a&gt; 视图文件目录&lt;/h3&gt;
&lt;p&gt;&lt;code&gt;resources\views&lt;/code&gt;  视图也可以分目录管理的&lt;/p&gt;
&lt;h3 id=&#34;视图命名与渲染&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#视图命名与渲染&#34;&gt;#&lt;/a&gt; 视图命名与渲染&lt;/h3&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;文件名习惯小写 (建议小写)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;文件名的后缀是.blade.php (因为 laravel 里面有一套模板引擎就是使用 blade, 可以直接使用标签语法 &lt;code&gt;&amp;#123;&amp;#123;$title&amp;#125;&amp;#125;&lt;/code&gt; , 也可以使用原生的 php 语法显示数据)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;需要注意的是也可以使用.php 结尾，但是这样的话就不能使用 laravel 提供的标签 &lt;code&gt;&amp;#123;&amp;#123;$title&amp;#125;&amp;#125;&lt;/code&gt;  语法显示数据，只能使用原生语法 &lt;code&gt;&amp;lt;?php echo $title; ?&amp;gt;&lt;/code&gt;  显示数据 两个视图文件同时存在，则 &lt;code&gt;.blade.php&lt;/code&gt;  后缀的优先显示。&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;展示视图的方法:
return view(&#39;视图文件的名称&#39;);
视图可以进行分目录管理的,例如需要展示home/test3视图,则可以写成:
return view(&#39;home/test3&#39;)
当然也支持点写法:
return view(&#39;home.test3&#39;)
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;变量分配与展示&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#变量分配与展示&#34;&gt;#&lt;/a&gt; 变量分配与展示&lt;/h3&gt;
&lt;pre&gt;&lt;code&gt;语法:
view(模板文件名称,数组)   //数组就是需要分配的变量集合,数组是一个键值数组,其键与变量名一致
view(模板文件名称-&amp;gt;with(数组)
view(模板文件名称)-&amp;gt;with(名称,值)-&amp;gt;with(名称,值)
使用view()方式渲染一个视图后，在.blade.php_的视图文件中，模板中输出变量使用&amp;quot;&amp;#123;&amp;#123;$变量名&amp;#125;&amp;#125;&amp;quot;(变量名就是分配过来数组的键)
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;compact函数使用传参&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#compact函数使用传参&#34;&gt;#&lt;/a&gt; compact 函数使用 (传参)&lt;/h3&gt;
&lt;p&gt;compact 是 php 中内置的函数与 laravel 框架无关。作用：用于打包数组.&lt;/p&gt;
&lt;pre&gt;&lt;code&gt;语法:
compact(&#39;变量名1&#39;,&#39;变量名2&#39;....)
案例:
$date = date(&#39;Y-m-d H:i:s&#39;,time());
$day = &#39;二&#39;;
return view(&#39;home/home&#39;,compact(&#39;date&#39;,&#39;day&#39;));
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;模板中直接使用函数&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#模板中直接使用函数&#34;&gt;#&lt;/a&gt; 模板中直接使用函数&lt;/h3&gt;
&lt;p&gt;在 laravel 中。视图调用函数其语法基本与 js、php 的语法一致，只不过要求左右包含大括号：语法: &lt;code&gt;&amp;#123;&amp;#123;函数名(参数1,参数2…)&amp;#125;&amp;#125;&lt;/code&gt;  说明：函数名可以是 php 内置的。也可以是 laravel 框架中定义的&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code&gt;案例:在数据库中一般存储时间都是以时间戳去存储的,但是在页面上展示的时候不适合使用时间戳了.需要在展示的时候再对其进行格式化处理，如需要在视图中进行对其格式化则怎么写?
TestController.php(控制器):
public function home()&amp;#123;
$date = date(&#39;Y-m-d H:i:s&#39;,time());
$day = &#39;二&#39;;
//传递时间戳
//一年后的时间戳
$time = strtotime(&#39;+1 year&#39;);//一个月 +1 month,week
return view(&#39;home/home&#39;,compact(&#39;date&#39;,&#39;day&#39;,&#39;time&#39;));
&amp;#125;

view视图文件中调用函数:
一年之后的时间是:&amp;#123;&amp;#123;date(&#39;Y-m-d H:i:s&#39;,$time)&amp;#125;&amp;#125;
&lt;/code&gt;&lt;/pre&gt;
&lt;h3 id=&#34;循环与分支语法标签&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#循环与分支语法标签&#34;&gt;#&lt;/a&gt; 循环与分支语法标签&lt;/h3&gt;
&lt;pre&gt;&lt;code&gt;1. 在视图里遍历数据
```php
在laravel中模版中循环输出数据,则需要遵循语法:
@foreach($variable as $key =&amp;gt; $value)
    //循环体
@endforeach
在此过程中需要注意的就是get查询到的结果集中每一条记录其实都是一个对象，因此在循环具体字段的时候需要注意使用对象调用属性的方式才可以获取其数据。
案例:
&amp;lt;table border=&amp;quot;1&amp;quot;&amp;gt;
    &amp;lt;tr&amp;gt;
        &amp;lt;td&amp;gt;id&amp;lt;/td&amp;gt;
        &amp;lt;td&amp;gt;姓名&amp;lt;/td&amp;gt;
        &amp;lt;td&amp;gt;年龄&amp;lt;/td&amp;gt;
        &amp;lt;td&amp;gt;email&amp;lt;/td&amp;gt;
    &amp;lt;/tr&amp;gt;
    @foreach($data as $key =&amp;gt; $value)
        &amp;lt;tr&amp;gt;
            &amp;lt;td&amp;gt;&amp;#123;&amp;#123;$value-&gt;id&amp;#125;&amp;#125;&amp;lt;/td&amp;gt;
            &amp;lt;td&amp;gt;&amp;#123;&amp;#123;$value-&gt;name&amp;#125;&amp;#125;&amp;lt;/td&amp;gt;
            &amp;lt;td&amp;gt;&amp;#123;&amp;#123;$value-&gt;age&amp;#125;&amp;#125;&amp;lt;/td&amp;gt;
            &amp;lt;td&amp;gt;&amp;#123;&amp;#123;$value-&gt;email&amp;#125;&amp;#125;&amp;lt;/td&amp;gt;
        &amp;lt;/tr&amp;gt;
    @endforeach
&amp;lt;/table&amp;gt;&amp;lt;/code&amp;gt;&amp;lt;/pre&amp;gt;
&amp;lt;ol start=&amp;quot;2&amp;quot;&amp;gt;
&amp;lt;li&amp;gt;在视图里执行if判断
&amp;lt;pre&amp;gt;&amp;lt;code class=&amp;quot;language-php&amp;quot;&amp;gt;语法:
@if(条件表达式1)
执行的语句1
@elseif()
执行的语句2
....
@else
默认的执行语句
@endif&amp;lt;/code&amp;gt;&amp;lt;/pre&amp;gt;
&amp;lt;h3&amp;gt;模板继承/包含&amp;lt;/h3&amp;gt;
&amp;lt;p&amp;gt;继承不仅仅在php类中存在,在视图中同样存在.一般是用于做有公共部分的页面.&amp;lt;/p&amp;gt;
&amp;lt;pre&amp;gt;&amp;lt;code class=&amp;quot;language-php&amp;quot;&amp;gt;
语法:@yield(&#39;名字&#39;)   在父级页面中的占位&amp;lt;/code&amp;gt;&amp;lt;/pre&amp;gt;&amp;lt;/li&amp;gt;
&amp;lt;/ol&amp;gt;
&amp;lt;p&amp;gt;演示:&amp;lt;/p&amp;gt;
&amp;lt;p&amp;gt;文件名:base.blade.php&amp;lt;/p&amp;gt;
&amp;lt;h1&amp;gt;我是头部&amp;lt;/h1&amp;gt;
&amp;lt;!--  可变区域  --&amp;gt;
&amp;lt;p&amp;gt;@yield(&#39;mainbody&#39;)&amp;lt;/p&amp;gt;
&amp;lt;!--  可变区域  --&amp;gt;
&amp;lt;h1&amp;gt;我是尾部&amp;lt;/h1&amp;gt;
&amp;lt;p&amp;gt;继承语法:
子模版中按以下语法书写:
@extends(&#39;需要继承的模版文件名&#39;)  //其名称是完整路径
通过section标签绑定区块/部件到父级页面,区块名称就是父级页面yield标签的参数名.
@section(&#39;区块名称&#39;)
代码
@endsction&amp;lt;/p&amp;gt;
&amp;lt;p&amp;gt;演示:&amp;lt;/p&amp;gt;
&amp;lt;p&amp;gt;文件名:test.blade.php
@extends(&#39;base&#39;) //如果是分目录管理请补全路径&amp;lt;/p&amp;gt;
&amp;lt;!--  指定yield标签的名字,绑定区块  -&amp;gt;
@section(&#39;mainboddy&#39;)
&amp;lt;div&amp;gt;
此行位置: display1函数运行结束:理论上局部变量$name应该已经被释放
$closure();//当前局部变量$name在$closure = display1();这一行display1函数运行结束后并没有被释放,从而在外部调用(也就是此行)内部匿名函数的时候可以被使用
&amp;lt;/div&amp;gt;
@endsction
&amp;lt;!--  文件的包含  --&amp;gt;
&amp;lt;p&amp;gt;@include(&#39;home.test4&#39;)&amp;lt;/p&amp;gt;
&amp;lt;pre&amp;gt;&amp;lt;code&amp;gt;### 外部静态文件引入方式
在写页面肯定会引入相关的外部文件(js、css、image),则会涉及到路径的问题.以下面的这个app.css为例,看如何去引入该css文件:
```php
以前的(首选):

在laravel中:
Asset方法中的参数可以是多级目录也可以是单级目录。
&lt;/code&gt;&lt;/pre&gt;
&lt;h2 id=&#34;laravel-csrf&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#laravel-csrf&#34;&gt;#&lt;/a&gt; Laravel-CSRF&lt;/h2&gt;
&lt;pre&gt;&lt;code&gt;案例:通过案例实现csrf的机制验证
1. 创建两个路由,一个用于展示表单(get),另外处理请求(post)
文件名:web.php(路由文件)
//CSRF验证
Route::get(&#39;home/test6&#39;,&#39;App\Http\Controllers\TestController@test6&#39;);
Route::post(&#39;home/test7&#39;,&#39;App\Http\Controllers\TestController@test7&#39;);

文件名:TestController.php
//展示基础的表单
public function test6()&amp;#123;
    return view(&#39;home/test6&#39;);
&amp;#125;
//处理请求
public function test7()&amp;#123;
    return &#39;处理成功&#39;;
&amp;#125;

文件名:test6.blade.php
&amp;lt;form action=&amp;quot;&amp;#123;&amp;#123;route(&#39;test7&#39;)&amp;#125;&amp;#125;&amp;quot; method=&amp;quot;post&amp;quot;&amp;gt;
姓名:&amp;lt;input type=&amp;quot;text&amp;quot; name=&amp;quot;name&amp;quot; value=&amp;quot;&amp;quot; placeholder=&amp;quot;请输入姓名&amp;quot;/&amp;gt;
&amp;#123;&amp;#123;csrf_field()&amp;#125;&amp;#125;
&amp;lt;input type=&amp;quot;submit&amp;quot; value=&amp;quot;提交&amp;quot;/&amp;gt;
&amp;lt;/form&amp;gt;

或:
&amp;lt;form action=&amp;quot;&amp;#123;&amp;#123;route(&#39;test7&#39;)&amp;#125;&amp;#125;&amp;quot; method=&amp;quot;post&amp;quot;&amp;gt;
姓名:&amp;lt;input type=&amp;quot;text&amp;quot; name=&amp;quot;name&amp;quot; value=&amp;quot;&amp;quot; placeholder=&amp;quot;请输入姓名&amp;quot;/&amp;gt;
&amp;lt;input type=&amp;quot;hidden&amp;quot; name=&amp;quot;_token&amp;quot; value=&amp;quot;&amp;#123;&amp;#123;csrf_token()&amp;#125;&amp;#125;&amp;quot;/&amp;gt;
&amp;lt;input type=&amp;quot;submit&amp;quot; value=&amp;quot;提交&amp;quot;/&amp;gt;
&amp;lt;/form&amp;gt;
&lt;/code&gt;&lt;/pre&gt;
&lt;p&gt;两者的区别: 1. csrf_token 只是输出 token 的值 2. csrf_field 输出了一个整个的 input 隐藏域 在后期使用的时候怎么选择：大部分情况下可以自己根据情况选择。但是有一个情况下开发者是没有选择权限的，必须需要使用 &lt;code&gt;csrf_token&lt;/code&gt;  的，这个情况就是使用异步提交表单的方式. 3.  &lt;code&gt;@csrf()&lt;/code&gt;  是 &lt;code&gt;&amp;#123;&amp;#123;csrf_field()&amp;#125;&amp;#125;&lt;/code&gt;  的简写&lt;/p&gt;
&lt;h3 id=&#34;从csrf验证中排除例外路由&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#从csrf验证中排除例外路由&#34;&gt;#&lt;/a&gt; 从 CSRF 验证中排除例外路由&lt;/h3&gt;
&lt;p&gt;并不是所有请求都需要避免 CSRF 攻击，比如去第三方 API 获取数据的请求 可以通过在 &lt;code&gt;VerifyCsrfToken(app/Http/Middleware/VerifyCsrfToken.php)&lt;/code&gt;  中间件中将要排除的请求 URL 添加到 &lt;code&gt;$except&lt;/code&gt;  属性数组中.&lt;/p&gt;
